Our GraphQL API is returning incorrect data for nested resolvers. When querying a user's posts with comments, some comments are showing up under the wrong post. It's inconsistent — sometimes the data is correct, sometimes comments are shuffled between posts.

```javascript
// src/schema/resolvers.js
const resolvers = {
  Query: {
    user: (_, { id }) => db.query('SELECT * FROM users WHERE id = $1', [id]).then(r => r.rows[0]),
  },
  User: {
    posts: (parent) => db.query('SELECT * FROM posts WHERE author_id = $1', [parent.id]).then(r => r.rows),
  },
  Post: {
    comments: (parent) => {
      // Using a shared dataloader to avoid N+1
      return commentLoader.load(parent.id);
    },
  },
};
```

```javascript
// src/loaders/commentLoader.js
const DataLoader = require('dataloader');

const commentLoader = new DataLoader(async (postIds) => {
  const result = await db.query(
    'SELECT * FROM comments WHERE post_id = ANY($1) ORDER BY created_at',
    [postIds]
  );
  // Group comments by post_id
  const commentsByPost = {};
  for (const comment of result.rows) {
    if (!commentsByPost[comment.post_id]) {
      commentsByPost[comment.post_id] = [];
    }
    commentsByPost[comment.post_id].push(comment);
  }
  return Object.values(commentsByPost);
});

module.exports = commentLoader;
```

